/* ============================================================
   HELPERS
   ============================================================ */

function getInitials(name) {
  return name
    .split(" ")
    .map((p) => p[0])
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

function timeAgo(ts) {
  const diff = Math.max(0, Date.now() - ts);
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "just now";
  if (mins === 1) return "1 min ago";
  if (mins < 60) return `${mins} mins ago`;
  const hrs = Math.floor(mins / 60);
  return `${hrs} hr${hrs > 1 ? "s" : ""} ago`;
}

// Shared data (tallies, activity feed, election state) is stored server-side
// via a Netlify Function backed by Netlify Blobs, so every visitor sees the
// same live results. Personal data (whether THIS browser has voted) is kept
// in localStorage, so it stays private to that device/browser.
async function storageGet(key, shared) {
  try {
    if (shared) {
      const res = await fetch(`/.netlify/functions/storage?key=${encodeURIComponent(key)}`);
      if (!res.ok) return null;
      const data = await res.json();
      return data && data.value !== undefined ? data.value : null;
    }
    return localStorage.getItem(key);
  } catch (e) {
    return null;
  }
}

async function storageSet(key, value, shared) {
  try {
    if (shared) {
      const res = await fetch(`/.netlify/functions/storage`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ key, value }),
      });
      return res.ok;
    }
    localStorage.setItem(key, value);
    return true;
  } catch (e) {
    return false;
  }
}

