function CandidateCard({ candidate, onVote, disabled, isMyChoice }) {
  return (
    <div className="relative bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col card-hover">
      <div className="h-1.5" style={{ backgroundColor: candidate.color }}></div>
      <div className="p-6 flex flex-col flex-1">
        <p
          className="text-[11px] font-bold uppercase tracking-[0.2em] mb-4"
          style={{ color: candidate.color }}
        >
          Ballot Position {candidate.id}
        </p>

        <div className="flex items-center gap-4 mb-4">
          <div
            className="w-16 h-16 rounded-full shrink-0 ring-4 ring-white shadow-md overflow-hidden"
            style={{ backgroundColor: candidate.color }}
          >
            {candidate.photo ? (
              <img src={candidate.photo} alt={candidate.name} className="w-full h-full object-cover object-top" />
            ) : (
              <div className="w-full h-full flex items-center justify-center text-white font-serif font-bold text-xl">
                {getInitials(candidate.name)}
              </div>
            )}
          </div>
          <div>
            <h3 className="font-serif font-bold text-lg text-slate-900 leading-snug">
              {candidate.name}
            </h3>
            {candidate.nickname && (
              <p className="text-xs font-bold uppercase tracking-wider mb-0.5" style={{ color: candidate.color }}>
                "{candidate.nickname}"
              </p>
            )}
            <p className="text-sm text-slate-500">{candidate.title}</p>
          </div>
        </div>

        <p className="text-sm text-slate-600 leading-relaxed flex-1">
          {candidate.manifesto}
        </p>

        {candidate.slogan && (
          <p className="mt-3 text-xs italic text-slate-400">{candidate.slogan}</p>
        )}

        <button
          onClick={() => onVote(candidate)}
          disabled={disabled}
          className={`mt-6 w-full font-semibold text-sm py-3 rounded-xl flex items-center justify-center gap-2 transition-all ${
            isMyChoice
              ? "bg-emerald-50 text-emerald-700 border border-emerald-200 cursor-default"
              : disabled
              ? "bg-slate-100 text-slate-400 cursor-not-allowed"
              : "text-white hover:scale-[1.02] shadow-sm"
          }`}
          style={!disabled && !isMyChoice ? { backgroundColor: candidate.color } : {}}
        >
          {isMyChoice ? (
            <>
              <CheckCircle2 className="w-4 h-4" /> Your vote
            </>
          ) : disabled ? (
            "Voting closed"
          ) : (
            <>
              <Vote className="w-4 h-4" /> Vote for {candidate.name.split(" ")[0]}
            </>
          )}
        </button>
      </div>
    </div>
  );
}

