/* ============================================================
   ADMIN PANEL
   ============================================================ */

function AdminPanel({ onClose, electionState, tallies, activity, onToggleVoting, onResetData, onResetMyVote }) {
  const [authed, setAuthed] = useState(false);
  const [pass, setPass] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [authError, setAuthError] = useState("");

  const totalVotes = CANDIDATES.reduce((sum, c) => sum + (tallies[c.id] || 0), 0);

  const login = () => {
    if (pass === ADMIN_PASSCODE) {
      setAuthed(true);
      setAuthError("");
    } else {
      setAuthError("Incorrect passcode.");
    }
  };

  const exportCSV = () => {
    const rows = [["Candidate", "Ballot Position", "Votes", "Percentage"]];
    CANDIDATES.forEach((c) => {
      const v = tallies[c.id] || 0;
      const pct = totalVotes ? ((v / totalVotes) * 100).toFixed(2) : "0.00";
      rows.push([c.name, c.id, v, `${pct}%`]);
    });
    rows.push(["Total", "", totalVotes, "100%"]);
    const csv = rows.map((r) => r.join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ksb-election-results-${Date.now()}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const pieData = CANDIDATES.map((c) => ({
    name: c.name,
    value: tallies[c.id] || 0,
    color: c.color,
  }));

  const barData = CANDIDATES.map((c) => ({
    name: c.name.split(" ")[0],
    votes: tallies[c.id] || 0,
    color: c.color,
  }));

  const isClosed =
    electionState.status === "closed" || Date.now() >= electionState.endTime;

  return (
    <div className="fixed inset-0 z-50 bg-[#F7F5EF] overflow-y-auto">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-8">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-2.5">
            <div className="w-9 h-9 rounded-lg bg-[#0B1B42] flex items-center justify-center">
              <KeyRound className="w-5 h-5 text-[#F4C84B]" />
            </div>
            <div>
              <p className="font-serif font-bold text-[#0B1B42] text-lg leading-tight">
                Election Committee Dashboard
              </p>
              <p className="text-xs text-slate-400">{PLATFORM_NAME} · Admin only</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="text-sm font-semibold text-slate-500 hover:text-slate-700 flex items-center gap-1.5"
          >
            <ArrowRight className="w-4 h-4 rotate-180" /> Back to site
          </button>
        </div>

        {!authed ? (
          <div className="max-w-sm mx-auto bg-white border border-slate-200 rounded-2xl p-8 mt-12">
            <div className="w-12 h-12 rounded-xl bg-[#0B1B42] flex items-center justify-center mb-4">
              <Lock className="w-5 h-5 text-[#F4C84B]" />
            </div>
            <h2 className="font-serif font-bold text-xl text-[#0B1B42] mb-1">
              Admin sign in
            </h2>
            <p className="text-sm text-slate-500 mb-5">
              Enter the election committee passcode to view results.
            </p>
            <div className="relative">
              <input
                type={showPass ? "text" : "password"}
                value={pass}
                onChange={(e) => setPass(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && login()}
                placeholder="Passcode"
                className="w-full border border-slate-300 rounded-lg px-4 py-3 pr-10 text-sm focus:outline-none focus:ring-2 focus:ring-[#1E40AF]/30 focus:border-[#1E40AF]"
              />
              <button
                onClick={() => setShowPass((s) => !s)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400"
              >
                {showPass ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            {authError && (
              <p className="mt-2 text-sm text-red-600 flex items-center gap-1.5">
                <AlertCircle className="w-4 h-4" /> {authError}
              </p>
            )}
            <button
              onClick={login}
              className="mt-5 w-full bg-[#0B1B42] hover:bg-[#16264f] text-white font-semibold text-sm py-3 rounded-xl transition-colors"
            >
              Sign in
            </button>
            <p className="mt-4 text-xs text-slate-400 text-center">
              Demo passcode: <span className="font-mono">{ADMIN_PASSCODE}</span>
              <br />
              Replace with real authentication in production.
            </p>
          </div>
        ) : (
          <div className="space-y-8 fade-up">
            {/* Controls */}
            <div className="bg-white border border-slate-200 rounded-2xl p-5 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
              <div>
                <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-1">
                  Election status
                </p>
                <p className="flex items-center gap-2 font-semibold text-slate-800">
                  {isClosed ? (
                    <>
                      <span className="w-2.5 h-2.5 rounded-full bg-slate-400"></span>
                      Voting closed
                    </>
                  ) : (
                    <>
                      <LiveDot /> Voting open
                    </>
                  )}
                </p>
              </div>
              <div className="flex flex-wrap gap-2">
                <button
                  onClick={onToggleVoting}
                  className={`flex items-center gap-2 text-sm font-semibold px-4 py-2.5 rounded-lg transition-colors ${
                    isClosed
                      ? "bg-emerald-600 hover:bg-emerald-700 text-white"
                      : "bg-red-600 hover:bg-red-700 text-white"
                  }`}
                >
                  {isClosed ? (
                    <>
                      <Play className="w-4 h-4" /> Resume voting
                    </>
                  ) : (
                    <>
                      <Pause className="w-4 h-4" /> Stop voting
                    </>
                  )}
                </button>
                <button
                  onClick={exportCSV}
                  className="flex items-center gap-2 text-sm font-semibold px-4 py-2.5 rounded-lg bg-[#0B1B42] hover:bg-[#16264f] text-white transition-colors"
                >
                  <Download className="w-4 h-4" /> Export CSV
                </button>
              </div>
            </div>

            {/* Stat cards */}
            <div className="grid sm:grid-cols-3 gap-4">
              <div className="bg-white border border-slate-200 rounded-2xl p-5">
                <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-1">
                  Total votes
                </p>
                <p className="font-mono font-bold text-3xl text-[#0B1B42]">
                  {totalVotes.toLocaleString()}
                </p>
              </div>
              {CANDIDATES.map((c) => {
                const v = tallies[c.id] || 0;
                const pct = totalVotes ? ((v / totalVotes) * 100).toFixed(1) : "0.0";
                return (
                  <div key={c.id} className="bg-white border border-slate-200 rounded-2xl p-5">
                    <p className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-1 truncate">
                      {c.name}
                    </p>
                    <div className="flex items-end justify-between">
                      <p className="font-mono font-bold text-3xl" style={{ color: c.color }}>
                        {v.toLocaleString()}
                      </p>
                      <p className="text-sm font-semibold text-slate-500">{pct}%</p>
                    </div>
                    <div className="mt-2 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                      <div
                        className="h-full rounded-full transition-all"
                        style={{ width: `${pct}%`, backgroundColor: c.color }}
                      ></div>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Charts */}
            <div className="grid lg:grid-cols-2 gap-6">
              <div className="bg-white border border-slate-200 rounded-2xl p-5">
                <p className="font-bold text-slate-800 mb-4">Votes by candidate</p>
                <div className="h-72">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={barData}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                      <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                      <YAxis allowDecimals={false} tick={{ fontSize: 12 }} />
                      <Tooltip />
                      <Bar dataKey="votes" radius={[6, 6, 0, 0]}>
                        {barData.map((entry, i) => (
                          <Cell key={i} fill={entry.color} />
                        ))}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
              <div className="bg-white border border-slate-200 rounded-2xl p-5">
                <p className="font-bold text-slate-800 mb-4">Vote share</p>
                <div className="h-72">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={pieData}
                        dataKey="value"
                        nameKey="name"
                        innerRadius={55}
                        outerRadius={90}
                        paddingAngle={3}
                      >
                        {pieData.map((entry, i) => (
                          <Cell key={i} fill={entry.color} />
                        ))}
                      </Pie>
                      <Tooltip />
                      <Legend
                        verticalAlign="bottom"
                        height={36}
                        formatter={(value) => (
                          <span className="text-xs text-slate-600">{value}</span>
                        )}
                      />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>

            {/* Recent activity table */}
            <div className="bg-white border border-slate-200 rounded-2xl p-5">
              <p className="font-bold text-slate-800 mb-4">Recent activity (anonymized)</p>
              <div className="max-h-64 overflow-y-auto divide-y divide-slate-100">
                {activity.length === 0 && (
                  <p className="text-sm text-slate-400 py-3">No votes recorded yet.</p>
                )}
                {activity.map((a) => (
                  <div key={a.id} className="flex items-center justify-between py-2.5 text-sm">
                    <span className="text-slate-600">Vote from {a.location}</span>
                    <span className="text-slate-400 text-xs">{timeAgo(a.time)}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Danger zone */}
            <div className="bg-white border border-dashed border-slate-300 rounded-2xl p-5">
              <p className="font-bold text-slate-800 mb-1">Demo tools</p>
              <p className="text-sm text-slate-500 mb-4">
                These actions only affect this demo's stored data — useful for
                testing the voting flow repeatedly.
              </p>
              <div className="flex flex-wrap gap-2">
                <button
                  onClick={onResetMyVote}
                  className="text-sm font-semibold px-4 py-2.5 rounded-lg border border-slate-300 text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Reset my voting status
                </button>
                <button
                  onClick={onResetData}
                  className="text-sm font-semibold px-4 py-2.5 rounded-lg border border-red-200 text-red-600 hover:bg-red-50 transition-colors"
                >
                  Reset all election data
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* ============================================================
   APP
   ============================================================ */

export default function App() {
  const [tallies, setTallies] = useState({ A: 0, B: 0, C: 0 });
  const [activity, setActivity] = useState([]);
  const [electionState, setElectionState] = useState({
    status: "open",
    endTime: Date.now() + VOTING_DURATION_HOURS * 60 * 60 * 1000,
  });
  const [voterRecord, setVoterRecord] = useState({ hasVoted: false, choice: null });
  const [now, setNow] = useState(Date.now());
  const [modalCandidate, setModalCandidate] = useState(null);
  const [modalOpenFlag, setModalOpenFlag] = useState(false);
  const [showAdmin, setShowAdmin] = useState(false);
  const [voteFlash, setVoteFlash] = useState(false);
  const [loaded, setLoaded] = useState(false);

  const totalVotes = CANDIDATES.reduce((sum, c) => sum + (tallies[c.id] || 0), 0);

  // Load initial state
  useEffect(() => {
    let mounted = true;
    (async () => {
      // Election state
      let es = await storageGet(STORAGE_KEYS.electionState, true);
      if (es) {
        es = JSON.parse(es);
      } else {
        es = {
          status: "open",
          endTime: Date.now() + VOTING_DURATION_HOURS * 60 * 60 * 1000,
        };
        await storageSet(STORAGE_KEYS.electionState, JSON.stringify(es), true);
      }

      // Tallies
      let t = await storageGet(STORAGE_KEYS.tallies, true);
      if (t) {
        t = JSON.parse(t);
      } else {
        t = { A: 0, B: 0, C: 0 };
        await storageSet(STORAGE_KEYS.tallies, JSON.stringify(t), true);
      }

      // Activity
      let act = await storageGet(STORAGE_KEYS.activity, true);
      act = act ? JSON.parse(act) : [];

      // Voter record (personal)
      let vr = await storageGet(STORAGE_KEYS.voterRecord, false);
      vr = vr ? JSON.parse(vr) : { hasVoted: false, choice: null };

      if (mounted) {
        setElectionState(es);
        setTallies(t);
        setActivity(act);
        setVoterRecord(vr);
        setLoaded(true);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  // Tick clock
  useEffect(() => {
    const id = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(id);
  }, []);

  // Poll shared state for "real-time" updates
  useEffect(() => {
    if (!loaded) return;
    const id = setInterval(async () => {
      const t = await storageGet(STORAGE_KEYS.tallies, true);
      if (t) setTallies((prev) => ({ ...prev, ...JSON.parse(t) }));

      const act = await storageGet(STORAGE_KEYS.activity, true);
      if (act) setActivity(JSON.parse(act));

      const es = await storageGet(STORAGE_KEYS.electionState, true);
      if (es) setElectionState(JSON.parse(es));
    }, 5000);
    return () => clearInterval(id);
  }, [loaded]);

  const msLeft = Math.max(0, electionState.endTime - now);
  const votingOpen = electionState.status === "open" && msLeft > 0;

  const openVoteModal = useCallback(
    (candidate) => {
      setModalCandidate(candidate || CANDIDATES[0]);
      setModalOpenFlag(true);
    },
    []
  );

  const scrollToCandidates = () => {
    const el = document.getElementById("candidates");
    if (el) el.scrollIntoView({ behavior: "smooth" });
  };

  const handleVoteSuccess = async (candidateId) => {
    // Update tallies
    const latestRaw = await storageGet(STORAGE_KEYS.tallies, true);
    const latest = latestRaw ? JSON.parse(latestRaw) : tallies;
    const updated = { ...latest, [candidateId]: (latest[candidateId] || 0) + 1 };
    await storageSet(STORAGE_KEYS.tallies, JSON.stringify(updated), true);
    setTallies(updated);

    // Update activity feed
    const actRaw = await storageGet(STORAGE_KEYS.activity, true);
    const act = actRaw ? JSON.parse(actRaw) : [];
    const entry = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      time: Date.now(),
      location: ACTIVITY_LOCATIONS[Math.floor(Math.random() * ACTIVITY_LOCATIONS.length)],
    };
    const newAct = [entry, ...act].slice(0, 30);
    await storageSet(STORAGE_KEYS.activity, JSON.stringify(newAct), true);
    setActivity(newAct);

    // Update voter record (personal)
    const record = { hasVoted: true, choice: candidateId, votedAt: Date.now() };
    await storageSet(STORAGE_KEYS.voterRecord, JSON.stringify(record), false);
    setVoterRecord(record);

    setVoteFlash(true);
    setTimeout(() => setVoteFlash(false), 600);
  };

  const handleToggleVoting = async () => {
    const isClosed = electionState.status === "closed" || msLeft <= 0;
    const updated = {
      status: isClosed ? "open" : "closed",
      endTime: isClosed
        ? Date.now() + VOTING_DURATION_HOURS * 60 * 60 * 1000
        : electionState.endTime,
    };
    await storageSet(STORAGE_KEYS.electionState, JSON.stringify(updated), true);
    setElectionState(updated);
  };

  const handleResetData = async () => {
    if (!window.confirm("Reset all votes and activity for this demo?")) return;
    const t = { A: 0, B: 0, C: 0 };
    await storageSet(STORAGE_KEYS.tallies, JSON.stringify(t), true);
    await storageSet(STORAGE_KEYS.activity, JSON.stringify([]), true);
    setTallies(t);
    setActivity([]);
  };

  const handleResetMyVote = async () => {
    const record = { hasVoted: false, choice: null };
    await storageSet(STORAGE_KEYS.voterRecord, JSON.stringify(record), false);
    setVoterRecord(record);
  };

  return (
    <div className="min-h-screen bg-[#F7F5EF] text-slate-800 font-sans">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Source+Serif+4:wght@600;700&family=Inter:wght@400;500;600;700&display=swap');
        .font-serif { font-family: 'Source Serif 4', Georgia, serif; }
        .font-sans { font-family: 'Inter', system-ui, sans-serif; }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(16px); } to { opacity: 1; transform: translateY(0); } }
        .fade-up { animation: fadeUp 0.7s ease-out; }
        @keyframes flapIn { from { transform: translateY(-6px); opacity: 0.5; } to { transform: translateY(0); opacity: 1; } }
        .flap-tile { animation: flapIn 0.35s ease-out; }
        @keyframes modalPop { from { opacity: 0; transform: scale(0.96) translateY(8px); } to { opacity: 1; transform: scale(1) translateY(0); } }
        .modal-pop { animation: modalPop 0.25s ease-out; }
        @keyframes successPop { 0% { transform: scale(0.5); opacity: 0; } 70% { transform: scale(1.1); } 100% { transform: scale(1); opacity: 1; } }
        .success-pop { animation: successPop 0.5s ease-out; }
        .dot-grid { background-image: radial-gradient(circle, #ffffff 1px, transparent 1px); background-size: 22px 22px; }
        .card-hover { transition: transform 0.25s ease, box-shadow 0.25s ease; }
        .card-hover:hover { transform: translateY(-4px); box-shadow: 0 12px 30px -12px rgba(11,27,66,0.25); }
      `}</style>

      <Header onVoteNow={scrollToCandidates} onAdmin={() => setShowAdmin(true)} votingOpen={votingOpen} />

      <Hero
        onVoteNow={scrollToCandidates}
        votingOpen={votingOpen}
        msLeft={msLeft}
        totalVotes={totalVotes}
        voteFlash={voteFlash}
      />

      <CandidatesSection votingOpen={votingOpen} voterRecord={voterRecord} onVote={openVoteModal} />

      <HowItWorks />

      <ActivityFeed activity={activity} totalVotes={totalVotes} />

      <Footer onAdmin={() => setShowAdmin(true)} />

      {modalOpenFlag && (
        <VotingModal
          candidate={modalCandidate}
          votingOpen={votingOpen}
          voterRecord={voterRecord}
          tallies={tallies}
          onClose={() => setModalOpenFlag(false)}
          onVoteSuccess={handleVoteSuccess}
        />
      )}

      {showAdmin && (
        <AdminPanel
          onClose={() => setShowAdmin(false)}
          electionState={electionState}
          tallies={tallies}
          activity={activity}
          onToggleVoting={handleToggleVoting}
          onResetData={handleResetData}
          onResetMyVote={handleResetMyVote}
        />
      )}
    </div>
  );
}
